      tickerShowLogo: screen.tickerShowLogo !== false,
      tickerLayout: screen.tickerLayout || "marquee",
      sourceMode: screen.sourceMode || "school",
      linkedClassroomId: screen.linkedClassroomId ? String(screen.linkedClassroomId) : "",
